GSD_TOOLS="$HOME/.claude/gsd-core/bin/gsd-tools.cjs"; gsd_run() { node "$GSD_TOOLS" "$@"; }
echo "=== plan:pre active hooks (kinds + capIds + into) ==="
gsd_run loop render-hooks plan:pre --raw 2>/dev/null | node -e '
let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{
  try{const j=JSON.parse(s);const h=j.activeHooks||j.hooks||[];
    if(!Array.isArray(h)||h.length===0){console.log("(no active plan:pre hooks)");return;}
    for(const e of h){console.log(`- kind=${e.kind} capId=${e.capId||""} into=${e.into||""} ref=${JSON.stringify(e.ref||{})} blocking=${e.blocking}`);}
  }catch(err){console.log("parse error:",err.message);console.log(s.slice(0,500));}
});'
