echo "=== planner contribution fragments + security configValues ==="
gsd_run loop render-hooks plan:pre --raw 2>/dev/null | node -e '
let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{
  const j=JSON.parse(s);const h=j.activeHooks||j.hooks||[];
  for(const e of h){
