      console.log("### capId="+e.capId);
      if(e.configValues) console.log("configValues="+JSON.stringify(e.configValues));
      const frag=(e.fragment&&(e.fragment.inline||e.fragment.text))||"";
      console.log("fragment.inline:\n"+frag+"\n---END---\n");
    }
  }
});'

